import{_ as a,o as n,c as o,ak as l}from"./chunks/framework.DLt_otXO.js";const y=JSON.parse('{"title":"路由传参","description":"","frontmatter":{"title":"路由传参","date":"2021-12-30T16:13:30.000Z","permalink":"/pages/24aedb/","categories":["框架","VueRouter"],"tags":[null]},"headers":[],"relativePath":"框架/VueRouter/路由组件传参.md","filePath":"框架/VueRouter/路由组件传参.md","lastUpdated":1777258973000}'),e={name:"框架/VueRouter/路由组件传参.md"};function p(c,s,t,r,E,d){return n(),o("div",null,[...s[0]||(s[0]=[l(`<h2 id="_1-简介" tabindex="-1">1. 简介 <a class="header-anchor" href="#_1-简介" aria-label="Permalink to “1. 简介”">​</a></h2><p>在组件中，使用<code>$route</code>也能获取到路由参数(<code>$route.params</code>或<code>$route.query</code>)，但是<code>$route</code>会与路由紧密耦合，这限制了组件的灵活性，因为它只能用于特定的<code>URL</code>。我们也可以通过<code>props</code>配置来解除这种行为。</p><p>我们可以将下面的代码：</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#F97583;">const</span><span style="color:#79B8FF;"> User</span><span style="color:#F97583;"> =</span><span style="color:#E1E4E8;"> {</span></span>
<span class="line"><span style="color:#E1E4E8;">  template: </span><span style="color:#9ECBFF;">&quot;&lt;div&gt;User {{$route.params.id}}&lt;/div&gt;&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">};</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F97583;">const</span><span style="color:#79B8FF;"> routes</span><span style="color:#F97583;"> =</span><span style="color:#E1E4E8;"> [{ path: </span><span style="color:#9ECBFF;">&quot;/user/:id&quot;</span><span style="color:#E1E4E8;">, component: User }];</span></span></code></pre></div><p>替换成：</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#F97583;">const</span><span style="color:#79B8FF;"> User</span><span style="color:#F97583;"> =</span><span style="color:#E1E4E8;"> {</span></span>
<span class="line"><span style="color:#E1E4E8;">  props: [</span><span style="color:#9ECBFF;">&quot;id&quot;</span><span style="color:#E1E4E8;">],</span></span>
<span class="line"><span style="color:#E1E4E8;">  template: </span><span style="color:#9ECBFF;">&quot;&lt;div&gt;User {{id}}&lt;/div&gt;&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">};</span></span>
<span class="line"><span style="color:#F97583;">const</span><span style="color:#79B8FF;"> routes</span><span style="color:#F97583;"> =</span><span style="color:#E1E4E8;"> [{ path: </span><span style="color:#9ECBFF;">&quot;/user/:id&quot;</span><span style="color:#E1E4E8;">, component: User, props: </span><span style="color:#79B8FF;">true</span><span style="color:#E1E4E8;"> }];</span></span></code></pre></div><h2 id="_2-分类" tabindex="-1">2. 分类 <a class="header-anchor" href="#_2-分类" aria-label="Permalink to “2. 分类”">​</a></h2><h3 id="_2-1-布尔模式" tabindex="-1">2.1 布尔模式 <a class="header-anchor" href="#_2-1-布尔模式" aria-label="Permalink to “2.1 布尔模式”">​</a></h3><p>当<code>props</code>设置为<code>true</code>时，<code>route.params</code>将被设置为组件的<code>props</code></p><h3 id="_2-2-命名视图" tabindex="-1">2.2 命名视图 <a class="header-anchor" href="#_2-2-命名视图" aria-label="Permalink to “2.2 命名视图”">​</a></h3><p>对于有命名视图的路由，你必须为每个命名视图定义<code>props</code>配置</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#F97583;">const</span><span style="color:#79B8FF;"> routes</span><span style="color:#F97583;"> =</span><span style="color:#E1E4E8;"> [</span></span>
<span class="line"><span style="color:#E1E4E8;">  {</span></span>
<span class="line"><span style="color:#E1E4E8;">    path: </span><span style="color:#9ECBFF;">&quot;/user:id&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">    component: { default: User, sidebar: Sidebar },</span></span>
<span class="line"><span style="color:#E1E4E8;">    props: { default: </span><span style="color:#79B8FF;">true</span><span style="color:#E1E4E8;">, sidebar: </span><span style="color:#79B8FF;">false</span><span style="color:#E1E4E8;"> },</span></span>
<span class="line"><span style="color:#E1E4E8;">  },</span></span>
<span class="line"><span style="color:#E1E4E8;">];</span></span></code></pre></div><h3 id="_2-3-对象模式" tabindex="-1">2.3 对象模式 <a class="header-anchor" href="#_2-3-对象模式" aria-label="Permalink to “2.3 对象模式”">​</a></h3><p>当<code>props</code>是一个对象时，它将原样设置为组件<code>props</code>。当<code>props</code>是静态的时候很有用。</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#6A737D;">// 路由配置</span></span>
<span class="line"><span style="color:#F97583;">const</span><span style="color:#79B8FF;"> routes</span><span style="color:#F97583;"> =</span><span style="color:#E1E4E8;"> [</span></span>
<span class="line"><span style="color:#E1E4E8;">  {</span></span>
<span class="line"><span style="color:#E1E4E8;">    path: </span><span style="color:#9ECBFF;">&quot;/hello&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">    component: Hello,</span></span>
<span class="line"><span style="color:#E1E4E8;">    props: { name: </span><span style="color:#9ECBFF;">&quot;World&quot;</span><span style="color:#E1E4E8;"> },</span></span>
<span class="line"><span style="color:#E1E4E8;">  },</span></span>
<span class="line"><span style="color:#E1E4E8;">];</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;">// 组件获取</span></span>
<span class="line"><span style="color:#F97583;">const</span><span style="color:#79B8FF;"> Hello</span><span style="color:#F97583;"> =</span><span style="color:#E1E4E8;"> {</span></span>
<span class="line"><span style="color:#E1E4E8;">  props: {</span></span>
<span class="line"><span style="color:#E1E4E8;">    name: {</span></span>
<span class="line"><span style="color:#E1E4E8;">      type: String,</span></span>
<span class="line"><span style="color:#E1E4E8;">      default: </span><span style="color:#9ECBFF;">&quot;Vue&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">    },</span></span>
<span class="line"><span style="color:#E1E4E8;">  },</span></span>
<span class="line"><span style="color:#E1E4E8;">  template: </span><span style="color:#9ECBFF;">&quot;&lt;div&gt; Hello {{ name }}&lt;/div&gt;&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">};</span></span></code></pre></div><p><code>Hello</code>组件默认显示<code>Hello Vue</code>，但是路由配置了<code>props</code>对象，当路由跳转到<code>/hello</code>时，会显示传递过来的<code>name</code>,页面将显示<code>Hello World</code></p><h3 id="_2-4-函数模式" tabindex="-1">2.4 函数模式 <a class="header-anchor" href="#_2-4-函数模式" aria-label="Permalink to “2.4 函数模式”">​</a></h3><p>我们可以创建一个返回<code>props</code>的函数。这允许我们<strong>将参数转换为其他类型，将静态值与基于路由的值想结合等等</strong></p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#F97583;">const</span><span style="color:#79B8FF;"> routes</span><span style="color:#F97583;"> =</span><span style="color:#E1E4E8;"> [</span></span>
<span class="line"><span style="color:#E1E4E8;">  {</span></span>
<span class="line"><span style="color:#E1E4E8;">    path: </span><span style="color:#9ECBFF;">&quot;/search&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#E1E4E8;">    component: SearchUser,</span></span>
<span class="line"><span style="color:#B392F0;">    props</span><span style="color:#E1E4E8;">: (</span><span style="color:#FFAB70;">route</span><span style="color:#E1E4E8;">) </span><span style="color:#F97583;">=&gt;</span><span style="color:#E1E4E8;"> ({ query: route.query.q }),</span></span>
<span class="line"><span style="color:#E1E4E8;">  },</span></span>
<span class="line"><span style="color:#E1E4E8;">];</span></span></code></pre></div><p>url <code>/search?q=vue</code>将传递<code>{query:&#39;vue&#39;}</code>作为<code>props</code>传递给<code>SearchUser</code>组件</p>`,20)])])}const u=a(e,[["render",p]]);export{y as __pageData,u as default};
